9671           else if (Pred == ICmpInst::ICMP_SGT && match(B, m_AllOnes()))
9672             InsertAffected(X);
9673         }
9674       }
9675     } else if (match(Cond, m_FCmp(Pred, m_Value(A), m_Value(B)))) {
9676       AddCmpOperands(A, B);
9677 
9678       // fcmp fneg(x), y
9679       // fcmp fabs(x), y
9680       // fcmp fneg(fabs(x)), y
9681       if (match(A, m_FNeg(m_Value(A))))
9682         AddAffected(A);
9683       if (match(A, m_FAbs(m_Value(A))))
9684         AddAffected(A);
9685 
9686     } else if (match(V, m_Intrinsic<Intrinsic::is_fpclass>(m_Value(A),
9687                                                            m_Value()))) {
9688       // Handle patterns that computeKnownFPClass() support.
9689       AddAffected(A);
9690     }
9691   }
